import requests
import pandas as pd
from io import StringIO

LIPIDMAPS_URL = "https://www.lipidmaps.org/ms/rest/ms_search/"

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Return the number of unique input m/z values that yield at least one match."""
    # Preprocess m/z string: skip empty lines, non-numeric lines, and strip whitespace
    valid_mzs = []
    for line in mzStr.splitlines():
        stripped = line.strip()
        if stripped == '':
            continue
        try:
            float(stripped)
            valid_mzs.append(stripped)
        except ValueError:
            continue
    if not valid_mzs:
        return 0
    mzStr_clean = '\n'.join(valid_mzs)

    # Clean adducts string: remove extra spaces
    adducts_clean = ','.join([a.strip() for a in adducts.split(',')])

    files = {'file': ('file', StringIO(mzStr_clean), 'text/plain')}
    data = {
        'CHOICE': db,
        'ion': adducts_clean,
        'tol': str(tolerance),
        'sort': 'DELTA'
    }
    try:
        response = requests.post(LIPIDMAPS_URL, data=data, files=files)
    except Exception:
        raise Exception('Connection error with the database. Please check your network and try again after a few minutes.')
    if len(response.text) == 0:
        return 0
    try:
        matches = pd.read_csv(StringIO(response.text), sep='\t', engine='python')
    except Exception:
        return 0
    if matches.empty:
        return 0
    # Handle variable column names for input mass
    possible_columns = ['Input Mass', 'Input m/z', 'Mass']
    input_col = None
    for col in possible_columns:
        if col in matches.columns:
            input_col = col
            break
    if input_col is None:
        # fallback to first column if unknown
        input_col = matches.columns[0]
    unique_masses = matches[input_col].unique()
    return len(unique_masses)
